export class VerifyEmailComponent implements OnInit {
  verifying = true;
  verifyFailed = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private accountService: AccountService,
    private alertService: AlertService
  ) { }

  ngOnInit() {
    const token = this.route.snapshot.queryParams['token'];
    this.accountService.verifyEmail(token)
      .pipe(first())
      .subscribe({
        next: () => {
          this.alertService.success('Verification successful, you can now login', { keepAfterRouteChange: true });
          this.router.navigate(['/account/login']);
        },
        error: () => {
          this.verifyFailed = true;
          this.verifying = false;
        }
      });
  }
}
<h4 class="card-title mb-4">Verify Email</h4>
<div *ngIf="verifying">
  <span class="spinner-border spinner-border-sm me-1"></span>
  Verifying...
</div>
<div *ngIf="!verifying && verifyFailed" class="text-danger">
  <p>Verification failed. Please try again or use the forgot password page to verify your account.</p>
  <a routerLink="/account/forgot-password">Forgot password</a>
</div>
